from odoo import fields, models, api
from odoo.exceptions import ValidationError
from odoo.addons.common_logging.logging_bootstrap import get_addon_loggers

LOG = get_addon_loggers("project_bom")


class ProjectItemBomLine(models.Model):

    _name = 'project.item.bom.line'
    _description = 'Project Item BOM Line'

    project_id = fields.Many2one('project.project', string='Project', required=True, ondelete='cascade')

    division_bom_id = fields.Many2one(
        'project.division.bom.item',
        string='Division',
        required=True,
        domain="[('project_id', '=', project_id)]"
    )

    product_id = fields.Many2one(
        'product.product', 
        string='Item', 
        required=True
    )

    quantity = fields.Float(string='QTY', default=1.0, required=True)

    category_id = fields.Many2one(
        'product.category', 
        string='Category', 
        related='product_id.categ_id', 
        readonly=True, store=True
    )

    base_markup = fields.Float(
        string='Markup (%)', 
        related='product_id.markup', 
        readonly=True, store=True
    )

    markup_modification = fields.Float(
        string='Markup Modification (+/- %)', 
        default=0.0
    )

    final_markup = fields.Float(
        string='Final Markup (%)',
        compute='_compute_final_markup',
        store=True, readonly=True
    )

    allowed_vendor_ids = fields.Many2many(
        'res.partner',
        compute='_compute_allowed_vendor_ids',
        store=False,
    )

    vendor_id = fields.Many2one(
        'res.partner', 
        string='Vendor', 
        required=False, 
    )

    avg_cost_per_qty = fields.Float(
        string='Avg Cost / Qty',
        compute='_compute_avg_cost_per_qty',
        store=True,
        readonly=True
    )

    final_estimated_price = fields.Float(
        string='Final Estimating Price',
        compute='_compute_final_estimated_price',
        store=True,
        readonly=True
    )


    @api.depends('base_markup', 'markup_modification')
    def _compute_final_markup(self):
        for line in self:
            line.final_markup = line.base_markup + line.markup_modification


    @api.depends('product_id')
    def _compute_allowed_vendor_ids(self):
        for line in self:
            if line.product_id:
                line.allowed_vendor_ids = line.product_id.seller_ids.mapped('partner_id')
            else:
                line.allowed_vendor_ids = [(5, 0, 0)]


    @api.onchange('product_id')
    def _onchange_product_id_set_vendor(self):
        if self.product_id:
            self._compute_allowed_vendor_ids()
            if self.allowed_vendor_ids:
                self.vendor_id = self.allowed_vendor_ids[0]
            else:
                self.vendor_id = False
        else:
            self.vendor_id = False


    @api.depends(
        'product_id',
        'product_id.product_tmpl_id.vendor_breakdown_ids.unit_qty',
        'product_id.product_tmpl_id.vendor_breakdown_ids.cost_for_unity_qty'
    )
    def _compute_avg_cost_per_qty(self):
        for line in self:
            if not line.product_id:
                line.avg_cost_per_qty = 0
                continue

            breakdowns = line.product_id.product_tmpl_id.vendor_breakdown_ids
            if not breakdowns:
                line.avg_cost_per_qty = 0
                continue

            per_qty_values = []
            for b in breakdowns:
                if b.unit_qty:
                    per_qty_values.append(b.cost_for_unity_qty)

            line.avg_cost_per_qty = (
                sum(per_qty_values) / len(per_qty_values)
                if per_qty_values else 0
            )


    @api.depends('quantity', 'final_markup', 'avg_cost_per_qty')
    def _compute_final_estimated_price(self):
        for line in self:
            total_cost = line.quantity * line.avg_cost_per_qty
            line.final_estimated_price = total_cost * (1 + line.final_markup / 100)




class ProjectProject(models.Model):

    _inherit = 'project.project'

    x_selected_division_id = fields.Many2one(
        'project.division.bom.item',
        string='Select Division/Installation',
        domain="[('project_id', '=', id)]",
        help='Select an installation to view its specific BOM lines.'
    )

    labor_bom_ids = fields.One2many(
        'labor.title.bom.line',
        'project_id',
        string='All Labor Titles'
    )

    x_filtered_labor_title_ids = fields.One2many(
        'labor.title.bom.line',
        'project_id',
        string='Labor Titles (Filtered)',
        compute='_compute_filtered_labor_title_ids',
        inverse='_inverse_filtered_labor_title_ids',
        readonly=False,
    )

    total_final_estimated_price = fields.Float(
        string="Total Final Estimated Price",
        compute="_compute_total_final_estimated_price",
        store=True,
        readonly=True
    )

    @api.depends('item_bom_ids.final_estimated_price')
    def _compute_total_final_estimated_price(self):
        for project in self:
            project.total_final_estimated_price = sum(
                project.item_bom_ids.mapped('final_estimated_price')
            )


    @api.depends('x_selected_division_id', 'labor_bom_ids.division_bom_id', 'labor_bom_ids.man_hours')
    def _compute_filtered_labor_title_ids(self):
        for project in self:
            if project.x_selected_division_id:
                project.x_filtered_labor_title_ids = project.labor_bom_ids.filtered(
                    lambda line: line.division_bom_id == project.x_selected_division_id
                )
            else:
                project.x_filtered_labor_title_ids = self.env['labor.title.bom.line']

    def _inverse_filtered_labor_title_ids(self):
        for project in self:
            if not project.x_selected_division_id:
                continue

            existing_lines_to_remove = project.labor_bom_ids.filtered(
                lambda line: line.division_bom_id == project.x_selected_division_id
            )

            other_lines_to_keep = project.labor_bom_ids - existing_lines_to_remove

            commands = [(6, 0, other_lines_to_keep.ids)]

            for line in project.x_filtered_labor_title_ids:
                line.project_id = project.id
                line.division_bom_id = project.x_selected_division_id

                values = line.read()[0]
                values.pop('id', None)

                for key, val in values.items():
                    if isinstance(val, tuple) and len(val) == 2 and isinstance(val[0], int):
                        values[key] = val[0]

                if line.id:
                    commands.append((1, line.id, values)) 
                else:
                    commands.append((0, 0, values))

            project.labor_bom_ids = commands


    item_bom_ids = fields.One2many(
        'project.item.bom.line',
        'project_id',
        string='All Item BOM Lines'
    )

    x_filtered_item_bom_ids = fields.One2many(
        'project.item.bom.line',
        'project_id',
        string='Item BOM Lines (Filtered)',
        compute='_compute_filtered_item_bom_ids',
        inverse='_inverse_filtered_item_bom_ids',
        readonly=False,
    )


    @api.depends('x_selected_division_id', 'item_bom_ids.division_bom_id', 'item_bom_ids')
    def _compute_filtered_item_bom_ids(self):
        for project in self:
            if project.x_selected_division_id:
                project.x_filtered_item_bom_ids = project.item_bom_ids.filtered(
                    lambda line: line.division_bom_id == project.x_selected_division_id
                )
            else:
                project.x_filtered_item_bom_ids = self.env['project.item.bom.line']


    def _inverse_filtered_item_bom_ids(self):
        for project in self:
            if not project.x_selected_division_id:
                LOG.info("Project %s: No division selected, skipping inverse", project.id)
                continue

            LOG.info(
                "Project %s: Processing inverse for division %s",
                project.id,
                project.x_selected_division_id.id,
            )

            existing_lines = project.item_bom_ids.filtered(
                lambda line: line.division_bom_id == project.x_selected_division_id
            )

            other_lines = project.item_bom_ids - existing_lines

            LOG.info(
                "Project %s: Existing lines for division: %s",
                project.id,
                existing_lines.ids,
            )
            LOG.info(
                "Project %s: Other division lines to keep: %s",
                project.id,
                other_lines.ids,
            )
            LOG.info(
                "Project %s: Filtered lines to process: %s",
                project.id,
                len(project.x_filtered_item_bom_ids),
            )

            new_records = []
            updated_count = 0
            created_count = 0
            deleted_count = 0

            for line in other_lines:
                new_records.append((4, line.id, 0))

            for line in project.x_filtered_item_bom_ids:
                values = line.read()[0]
                values.pop('id', None) 

                for key, val in values.items():
                    if isinstance(val, tuple) and len(val) == 2 and isinstance(val[0], int):
                        values[key] = val[0]
                    if isinstance(val, list) and all(isinstance(item, tuple) for item in val):
                        values[key] = [(6, 0, [item[0] for item in val])]

                values.pop('category_id', None)
                values.pop('base_markup', None)
                values.pop('final_markup', None)
                values.pop('allowed_vendor_ids', None)
                values.pop('display_name', None)
                values.pop('__last_update', None)

                values['project_id'] = project.id
                values['division_bom_id'] = project.x_selected_division_id.id

                if line.id and line.id in existing_lines.ids:
                    LOG.info(
                        "Project %s: Updating existing line %s with values: %s",
                        project.id,
                        line.id,
                        values,
                    )
                    new_records.append((1, line.id, values))
                    updated_count += 1
                else:
                    LOG.info(
                        "Project %s: Creating new line with values: %s",
                        project.id,
                        values,
                    )
                    new_records.append((0, 0, values)) 
                    created_count += 1

            filtered_ids = {line.id for line in project.x_filtered_item_bom_ids if line.id}
            lines_to_delete = existing_lines.filtered(lambda l: l.id not in filtered_ids)

            for line in lines_to_delete:
                LOG.info("Project %s: Deleting line %s", project.id, line.id)
                new_records.append((2, line.id, 0))
                deleted_count += 1

            LOG.info("Project %s: Final commands: %s", project.id, new_records)
            project.item_bom_ids = new_records
            LOG.summary(
                "Project BOM inverse completed for project %s division %s: updated=%s created=%s deleted=%s kept=%s",
                project.id,
                project.x_selected_division_id.id,
                updated_count,
                created_count,
                deleted_count,
                len(other_lines),
                surface_to_main=False,
            )


    @api.constrains('x_selected_division_id', 'x_filtered_item_bom_ids')
    def _check_division_required(self):
        for project in self:
            if project.x_filtered_item_bom_ids and not project.x_selected_division_id:
                raise ValidationError(
                    "You must select a 'Division for BOM View' when there are Item BOM Lines."
                )
